-- ───────────────────────────────────────────────────
--  FAQ（常见问题）新增 4 条：kb-faq-009 ~ 012
-- ───────────────────────────────────────────────────

INSERT IGNORE INTO `t_knowledge_base`
  (`id`,`tenant_id`,`category`,`title`,`content`,`keywords`,`source`)
VALUES
('kb-faq-009', NULL, 'faq', '如何导出报表和数据到Excel？',
'系统支持多种数据的Excel导出，操作方式如下：\n\n【生产订单报表】\n进入"生产管理 → 生产订单"，点击右上角"导出"按钮，可导出当前筛选结果为Excel。\n\n【工资结算报表】\n进入"财务 → 工资结算"，选择结算周期后点击"下载Excel"，支持按工厂/工序分组。\n\n【财务对账报表】\n进入"财务 → 对账管理"，点击"导出对账单"生成标准Excel格式。\n\n【智能日报/周报/月报】\n进入"智能驾驶舱 → 专业报告"，选择报告类型和时间范围后点击"下载Excel"。\n\n【注意事项】\n- 导出数据受权限控制，确保账号有对应模块的查看权限\n- 超大数据量导出可能需要30秒以上，请耐心等待\n- 导出文件默认保存到浏览器下载目录',
'导出,Excel,报表,下载', 'system'),

('kb-faq-010', NULL, 'faq', '洗水唛上的护理图标是什么意思？如何填写？',
'洗水唛护理图标遵循国际标准 ISO 3758，系统支持自动生成符合标准的图形符号。\n\n【五大类护理符号】\n1. 🫧 洗涤符号（桶形）：\n   - 30°C/40°C/60°C/95°C：最高洗涤温度\n   - 手洗（HAND）：只能手洗\n   - 禁洗（NO）：不可水洗\n\n2. △ 漂白符号（三角形）：\n   - 任何漂白剂（ANY）：允许所有漂白\n   - 非氯漂白（NON_CHL）：只用无氯漂白剂\n   - 禁止漂白（NO）：不可漂白\n\n3. ◻ 烘干符号（方形带圆/点）：\n   - 正常烘干（NORMAL）：标准温度滚筒烘干\n   - 低温烘干（LOW）：低温烘干\n   - 禁止烘干（NO）：不可机器烘干\n\n4. 熨烫符号（熨斗形）：\n   - 低温/中温/高温（LOW/MED/HIGH）\n   - 禁止熨烫（NO）\n\n5. 干洗符号（圆形）：\n   - 可干洗（YES）\n   - 禁止干洗（NO）\n\n【在系统中填写】\n进入"款式管理 → 款式详情 → 编辑"，在"护理信息"区域选择各项护理代码，系统会自动在洗水唛打印时生成对应SVG图形。',
'洗水唛,护理图标,ISO 3758,洗涤,漂白,烘干,熨烫,干洗,Care Label', 'system'),

('kb-faq-011', NULL, 'faq', '报废订单怎么处理？走什么流程？',
'报废订单是指因质量问题、客户取消等原因无法正常交货的订单，需要走正式的报废流程。\n\n【报废触发条件】\n- 客户取消订单且已开始生产\n- 成品质检不合格且无法返工\n- 原材料损毁导致无法完成生产\n\n【操作步骤】\n1. 进入"生产管理 → 生产订单"，找到需要报废的订单\n2. 点击操作列"更多 → 报废申请"\n3. 填写报废原因（必填）和报废数量\n4. 提交后等待主管审批\n5. 审批通过后，订单状态变更为"已报废"\n\n【报废后的财务处理】\n- 已生产的工序扫码记录不会被撤销（工人已完成的工作仍计工资）\n- 报废前确认库存已调整，避免库存虚高\n- 成本损失在月末财务对账中记录\n\n【注意】工资已结算的扫码记录禁止撤回，请在结算前处理完报废事项。',
'报废,取消订单,质检不合格,报废流程,损毁', 'system'),

('kb-faq-012', NULL, 'faq', '面料出现色差怎么处理？',
'面料色差是服装生产中常见问题，系统提供完整的处理追踪链路。\n\n【发现时机与分类】\n- 入库时发现色差：在面料入库界面勾选"质量异常"，填写异常描述后按正常流程入库但标记备注\n- 生产过程中发现：记录到对应的生产异常报告\n- 最终成品检验发现：在质检环节标记并拒绝入库\n\n【处理流程】\n1. 入库时标记异常批次（备注色差情况、色号、码数）\n2. 在采购管理中创建"质量索赔"跟单记录\n3. 联系供应商处理：换货/补货/折价\n4. AI助手可辅助：询问"面料色差如何处理"获取详细建议\n\n【预防措施】\n- 同批次面料入库时做对色检验\n- 批次号追踪（系统自动记录入库批次）\n- 核查材料数据库中该供应商历史色差记录',
'色差,面料质量,入库异常,质量索赔,批次追踪', 'system');

