INSERT IGNORE INTO `t_knowledge_base`
  (`id`,`tenant_id`,`category`,`title`,`content`,`keywords`,`source`)
VALUES
('kb-sop-004', NULL, 'sop', '出口服装洗水唛制作规范SOP（ISO 3758）',
'【适用范围】所有出口订单，贴有洗水唛的成品服装\n\n【制作步骤】\n\n**第一步：确认面料成分**\n- 在款式信息的"面料成分"字段填写，格式：90% Cotton / 10% Polyester\n- 多部位填写：使用"多部位面料成分"字段，分别填写 Upper(上身) / Lower(下身)\n\n**第二步：选择护理代码**\n根据面料特性在系统中选择：\n| 面料类型 | 洗涤 | 漂白 | 烘干 | 熨烫 | 干洗 |\n|--------|------|------|------|------|------|\n| 全棉 | W40 | NON_CHL | NORMAL | MED | NO |\n| 涤纶 | W30 | NO | LOW | LOW | NO |\n| 真丝 | HAND | NO | NO | LOW | YES |\n| 羊毛 | HAND | NO | NO | MED | YES |\n| 弹性面料(Spandex>5%) | W30 | NO | LOW | LOW | NO |\n\n**第三步：录入U编码**\n- U编码是品质追溯码，由客户提供或内部生成\n- 格式：字母+数字组合，例：UA2024001\n\n**第四步：打印洗水唛**\n- 进入"款式管理 → 款式详情 → 打印洗水唛"\n- 确认护理图标显示正确后打印\n- 建议打印样张交客户确认后批量印制\n\n**第五步：核对标准**\n- 欧盟市场：符合 EN ISO 3758:2012\n- 美国市场：符合 16 CFR Part 423 (FTC Care Labeling Rule)\n- 中国市场：符合 GB/T 8685-2008\n\n【QC检查点】每批成品随机抽取5%检查洗水唛内容与实际面料成分是否一致。',
'洗水唛,ISO 3758,Care Label,出口合规,面料成分,护理符号,EN ISO,FTC', 'system'),

('kb-sop-005', NULL, 'sop', '报废订单完整处理流程SOP',
'【触发条件】客户取消 / 质检不合格无法返工 / 原材料损毁\n\n【处理流程图】\n客户/质检反馈 → 跟单员评估 → 报废申请 → 主管审批 → 系统操作 → 财务确认\n\n【第一阶段：评估（当天完成）】\n1. 跟单员确认订单当前状态（生产中/质检中/入库前）\n2. 统计已完成工序和件数，估算损失\n3. 联系客户或工厂确认报废数量\n4. 在系统中创建报废申请单（填写原因+数量）\n\n【第二阶段：系统操作（审批通过后24小时内）】\n1. 财务在对账单中标记该订单为报废\n2. 仓库确认原材料库存是否需要调整\n3. 系统自动将订单状态变更为"已报废"\n4. AI助手可生成报废损失摘要报告\n\n【第三阶段：财务处理（月末）】\n1. 月末对账时单独列示报废损失明细\n2. 工人已完成的工序工资正常结算（不因报废扣减）\n3. 原材料损失记入当月成本\n4. 如有客户赔偿，在系统创建应收款记录\n\n【注意事项】\n- 报废前务必确认工资是否已结算，已结算记录不可撤回\n- 处理后通知仓管检查实物库存与系统数据一致性\n- 保留样品3个月以备客户投诉取证',
'报废,取消订单,损失处理,财务报废,工序工资,库存调整', 'system');

-- ───────────────────────────────────────────────────
--  系统操作指南（system_guide）新增 4 条：kb-guide-014 ~ 017
-- ───────────────────────────────────────────────────

INSERT IGNORE INTO `t_knowledge_base`
  (`id`,`tenant_id`,`category`,`title`,`content`,`keywords`,`source`)
VALUES
('kb-guide-014', NULL, 'system_guide', '如何打印洗水唛（支持护理图标自动生成）？',
'系统支持两个入口打印洗水唛：款式管理入口 和 生产订单入口。\n\n【从款式管理打印（推荐）】\n1. 进入"款式管理" → 找到需要的款式 → 点击"更多 → 打印洗水唛"\n2. 弹窗显示洗水唛预览，包含：\n   - 品牌标志区（如有）\n   - 面料成分（如：90%棉 10%涤纶）\n   - ISO 3758 护理图标（SVG矢量图，清晰可缩放）\n   - U编码/品质追溯码（可选）\n   - 产地（中国制造 / Made in China）\n3. 确认无误后点击"打印"\n\n【护理图标显示条件】\n- 需要在款式信息中填写"洗涤温度代码"等5个护理代码字段\n- 如未填写，自动降级为文字版洗涤说明\n- 建议出口订单必须填写护理代码以符合国际标准\n\n【多语言支持】\n- 护理符号为国际通用图形符号，无需翻译\n- 面料成分建议同时填写中英文（如：棉/Cotton）\n\n【打印设置】\n- 推荐打印尺寸：5cm × 3cm（标准领标尺寸）\n- 浏览器打印时选"实际大小"，不要缩放',
'洗水唛,打印,护理图标,Care Label,ISO 3758,SVG,面料成分,U编码', 'system'),

('kb-guide-015', NULL, 'system_guide', '如何使用"停滞订单预警"功能？',
'停滞订单预警功能帮助跟单员快速发现生产停滞、久未扫码的异常订单。\n\n【功能位置】\n生产管理 → 生产进度 → 订单列表（表格视图）\n在状态列右侧查看停滞标识。\n\n【停滞判定标准】\n- 订单状态为"进行中"（非已完成/已关闭）\n- 历史上有扫码记录\n- 最近3天无新的扫码记录\n→ 满足以上三个条件，订单行状态列自动显示橙色 ⏸ 停滞 标签\n\n【如何处理停滞订单】\n1. 点击停滞订单行，查看最后一次扫码时间和工序\n2. 联系对应工厂确认停滞原因（缺料/工人缺勤/设备故障）\n3. 在系统内添加催单备注，或使用"催单推送"发送手机通知\n4. 工厂恢复扫码后，⏸ 标签自动消失\n\n【催单推送设置】\n- 在订单详情页点击"催单"按钮\n- 填写催促内容和预期完成日期\n- 系统通过小程序将催单消息推送到工厂负责人手机\n- 工厂可在小程序直接回复（填写出货日期和备注）',
'停滞预警,停滞订单,扫码停止,催单,生产预警,异常订单', 'system'),

('kb-guide-016', NULL, 'system_guide', '如何查看"工厂产能雷达"评估工厂负荷？',
'工厂产能雷达展示各工厂当前承接订单的数量和风险状况，帮助合理分配新订单。\n\n【功能位置】\n生产管理 → 生产进度 → 过滤栏下方（工厂产能雷达面板）\n\n【面板内容说明】\n每家工厂展示4个关键数据：\n- 订单数：当前进行中的订单总数\n- 总件数：所有进行中订单的合计件数\n- 高风险数：进度<50%且货期≤7天的订单数量\n- 逃期数：已超过计划交货日期的订单数量\n\n【颜色编码含义】\n- 🟢 绿色：工厂负荷正常，高风险/逃期数量少，可以接新订单\n- 🟡 黄色：中等风险，建议谨慎安排新订单\n- 🔴 红色：高风险，该工厂已有多个逾期或高风险订单，不建议新增任务\n\n【使用场景】\n- 接到新客户订单时，先查产能雷达确认工厂是否有余力\n- 周会时用于评估各工厂整体健康状况\n- 帮助决策是否需要分单给另一家工厂',
'产能雷达,工厂产能,高风险,逾期,负荷,订单分配', 'system'),

('kb-guide-017', NULL, 'system_guide', '如何查看"订单健康度评分"识别高危订单？',
'订单健康度评分用3个维度实时评估每个订单的履约风险，帮助跟单员优先关注高危订单。\n\n【功能位置】\n生产管理 → 生产订单 → 订单号列（显示评分徽章）\n\n【评分算法（0-100分）】\n- 进度维度（40分）：当前生产进度百分比 × 40%\n- 货期维度（35分）：剩余天数越多得分越高（逾期=0分，>14天=35分）\n- 采购维度（25分）：采购物料到位率 × 25%\n\n【徽章显示规则】\n- ≥75分：不显示徽章（健康）\n- 50-74分：橙色「注」徽章（需关注）\n- <50分：红色「危」徽章（高危，优先处理）\n\n【如何处置「危」徽章订单】\n1. 点击订单号查看详情，重点查看：偏低的维度得分\n2. 进度低：在生产进度页触发催单流程\n3. 货期紧：联系客户协商交期延期，或启用加班计划\n4. 采购缺失：进入采购管理跟进缺货物料\n\n【刷新频率】\n- 健康度评分在打开订单列表时实时计算，无需手动刷新\n- 评分数据不占用额外API请求，不影响页面加载速度',
'订单健康度,评分,高危订单,注意,危险,货期风险,进度风险,采购风险', 'system');

-- ───────────────────────────────────────────────────
--  术语词典（terminology）新增 8 条：kb-term-009 ~ 016
-- ───────────────────────────────────────────────────

INSERT IGNORE INTO `t_knowledge_base`
  (`id`,`tenant_id`,`category`,`title`,`content`,`keywords`,`source`)
VALUES
('kb-term-009', NULL, 'terminology', '什么是洗水唛（Care Label）？',
'洗水唛（英文：Care Label）是缝制在服装内侧的小型标签，标注面料成分和洗涤护理方法。\n\n【洗水唛的内容】\n- 面料成分（Fabric Content）：如 100% Cotton / 90%棉10%涤\n- 护理符号（Care Symbols）：ISO 3758标准图形符号\n- 原产国（Country of Origin）：如 Made in China\n- 品质追溯码（U编码）：部分品牌要求填写\n\n【洗水唛的意义】\n- 消费者了解如何正确洗涤，延长服装寿命\n- 出口必须符合进口国法规（欧盟/美国/日本各有标准）\n- 质量纠纷时用于追溯生产批次\n\n【相关规范】\n- 国际：ISO 3758（护理符号）\n- 欧盟：EN ISO 3758:2012  \n- 美国：16 CFR Part 423\n- 中国：GB/T 8685-2008\n- 系统中通过款式信息填写并自动生成打印模板',
'洗水唛,Care Label,面料成分,护理符号,出口合规,GB/T 8685', 'system'),

('kb-term-010', NULL, 'terminology', 'ISO 3758 标准护理符号完整说明',
'ISO 3758是国际标准化组织发布的纺织品护理符号标准，共定义5类护理图标。\n\n【五大类符号】\n\n**1. 洗涤（桶形符号）**\n- 数字（30/40/60/95）= 最高洗涤温度\n- 桶内一条横线 = 轻柔洗涤\n- 桶内两条横线 = 非常轻柔\n- 手放桶中 = 手洗\n- 桶上打X = 禁止水洗\n\n**2. 漂白（三角形符号）**\n- 空三角 = 可用任何漂白剂\n- 三角内CL被划线 = 仅用无氯漂白剂\n- 三角上打X = 禁止漂白\n\n**3. 烘干（方形符号）**\n- 方圆内一圆 = 滚筒烘干（点越多温度越高）\n- 圆圈被X = 禁止机器烘干\n\n**4. 熨烫（熨斗形符号）**\n- 熨斗内点数 = 温度等级（1点低温/2点中温/3点高温）\n- 熨斗下有线 = 需垫布熨烫\n- 熨斗打X = 禁止熨烫\n\n**5. 专业护理（圆形符号）**\n- 圆A = 所有溶剂均可\n- 圆P = 氯乙烯以外溶剂\n- 圆F = 石油系溶剂\n- 圆W = 湿洗\n- 圆打X = 禁止专业洗涤',
'ISO 3758,护理符号,洗涤标识,漂白,烘干,熨烫,干洗,Care Label', 'system'),

('kb-term-011', NULL, 'terminology', '什么是SKU（库存单位）？',
'SKU（Stock Keeping Unit，库存单位）是区分商品的最小单位，用于精确追踪库存。\n\n【在服装行业的定义】\nSKU = 款式编号 + 颜色 + 尺码\n例：FZ2024001-红色-XL 是一个独立的SKU\n\n【为什么需要SKU】\n- 同一款式不同颜色/尺码的库存数量不同，需分开管理\n- 生产下单按SKU分配件数\n- 入库/出库按SKU追踪流向\n\n【在本系统中的应用】\n- 创建生产订单时，填写各SKU的件数（颜色×尺码矩阵）\n- 扫码时菲号绑定具体SKU\n- 库存查询可精确到每个SKU的可用数量\n\n【SKU vs 款号的区别】\n- 款号（Style No）：代表一个设计款式，如 FZ2024001\n- SKU：代表该款式下某颜色某尺码的具体规格\n- 一个款号可能对应数十个SKU（如5个颜色×7个尺码=35个SKU）',
'SKU,库存单位,款号,颜色,尺码,规格', 'system'),

('kb-term-012', NULL, 'terminology', '什么是BOM（原物料清单）？',
'BOM（Bill of Materials，原物料清单）是制作一件服装所需全部材料的清单，包含规格和用量。\n\n【服装BOM的组成内容】\n- 主面料：如棉布、涤纶、牛仔布（含用量、颜色、门幅）\n- 辅料：拉链、扣子、魔术贴、花边、弹力绳等\n- 包装材料：挂牌、颈标、洗水唛、包装袋等\n- 每项材料包含：物料名称、型号规格、单位、单件用量、总用量、供应商\n\n【BOM的作用】\n1. 采购依据：根据订单件数计算所需原材料总量\n2. 成本计算：乘以单价得出原材料总成本\n3. 缺料预警：系统自动对比库存，显示哪些物料需要采购\n4. 报价参考：AI助手可根据BOM自动计算款式总成本\n\n【在本系统中维护】\n进入"款式管理 → BOM清单"，逐行添加物料明细。建议填写完整的规格和供应商信息，方便复用和报价。',
'BOM,原物料清单,物料,辅料,面料,采购清单,成本计算', 'system'),

('kb-term-013', NULL, 'terminology', '什么是报废处理？与退货有什么区别？',
'报废（Scrap/Write-off）是将无法正常销售或使用的货品从系统库存中核销的操作，与退货处理方式不同。\n\n【报废的定义】\n报废是指货品因无法弥补的损坏、质量问题或客户取消而永久从库存中移除，通常无法收回成本。\n\n【报废 vs 退货的区别】\n| 对比项 | 报废 | 退货 |\n|------|------|------|\n| 货品状态 | 无法使用/销售 | 完好可重新入库 |\n| 成本处理 | 计入损失 | 冲减应付/应收 |\n| 系统操作 | 库存减少+损失记录 | 库存恢复+对账调整 |\n| 常见原因 | 质检不合格/火灾/损毁 | 客户不满意/错发货 |\n\n【报废分类】\n- 原材料报废：面料色差/损毁，填写面料出库报废\n- 半成品报废：生产中发现质量问题，按工序追踪损失\n- 成品报废：最终成品不合格，质检拒绝入库\n\n【对后续操作的影响】\n- 报废后该批次货品从可用库存中扣除\n- 已参与工资结算的扫码记录不受影响\n- 月末损益报表中体现报废损失',
'报废,退货,库存核销,质量不合格,成品报废,原材料报废,损失处理', 'system'),

('kb-term-014', NULL, 'terminology', '外贸出口价格术语速查：EXW/FOB/CIF/DDP',
'外贸价格条款（贸易术语/Incoterms）明确了买卖双方的责任边界和费用承担方式。\n\n【常见四种术语对比】\n\n**EXW（工厂交货价）**\n- 含义：货物在工厂门口交货\n- 卖方负责：生产、包装\n- 买方负责：内陆运输、出口清关、国际运费、进口清关\n- 适用：买方有能力自行安排出口物流\n\n**FOB（离岸价）**\n- 含义：货物装上指定出口港的船后交货\n- 卖方负责：货物+内陆运输+出口报关+装船费用\n- 买方负责：国际海运/空运+保险+目的港清关+目的地运输\n- 适用：最常见的出口报价方式\n\n**CIF（到岸价）**\n- 含义：成本+保险+运费到目的港\n- 比FOB多了：卖方承担国际运费和保险费\n- 适用：买方希望卖方负责送货到港\n\n**DDP（完税后交货）**\n- 含义：货物送到买方指定地点，含进口税\n- 卖方负责：全程到门包括目的国进口关税\n- 适用：买方完全无需操心物流\n\n【口诀】EXW → FOB → CIF → DDP：卖方承担责任依次递增',
'EXW,FOB,CIF,DDP,贸易术语,Incoterms,出口报价,离岸价,到岸价', 'system'),

('kb-term-015', NULL, 'terminology', '什么是面料缩水率（Shrinkage）？为什么重要？',
'缩水率（Shrinkage Rate）是指面料在洗涤后尺寸缩小的百分比，是制版和下料时的关键参数。\n\n【计算公式】\n缩水率 = (洗前尺寸 - 洗后尺寸) / 洗前尺寸 × 100%\n例：100cm → 97cm，缩水率 = 3%\n\n【各类面料参考缩水率】\n- 全棉：3%-5%（较高）\n- 棉涤混纺：1%-3%\n- 涤纶：0.5%-1%（低）\n- 真丝：2%-5%\n- 羊毛/毛混纺：3%-8%（最高）\n\n【对生产的影响】\n1. 制版放量：打版时需加入相应缩水余量\n2. BOM用量计算：采购面料时需多买缩水率对应的量\n3. 成衣规格达标：出货前洗水测试确认缩水后尺寸符合规格\n\n【在系统中的管理】\n- 材料数据库中可填写面料的缩水率参数\n- BOM用量字段可以包含缩水率损耗\n- AI助手可辅助计算含缩水率的BOM用量',
'缩水率,Shrinkage,面料,制版,放量,洗涤,BOM用量', 'system'),

('kb-term-016', NULL, 'terminology', '什么是颜色下单率？如何分析款式销售结构？',
'颜色下单率是指同一款式中，各颜色的订单件数占该款总件数的百分比，反映市场对不同颜色的偏好。\n\n【计算方式】\n颜色下单率 = 该颜色订单件数 / 该款式总订单件数 × 100%\n例：\n- 黑色：500件 / 1000件 = 50%\n- 白色：300件 / 1000件 = 30%\n- 红色：200件 / 1000件 = 20%\n\n【在系统中查看】\n进入"智能驾驶舱 → 经营分析"，可查看各款式各颜色的订单分布图表。\n\n【实际应用场景】\n1. 下一波订单备货决策：历史下单率高的颜色优先备料\n2. 面料采购优化：按颜色下单率分配面料采购量比例\n3. 新款颜色规划：参考历史畅销颜色开发新色系\n4. 库存风险预判：下单率低的颜色安全库存可适当降低\n\n【与尺码分布结合】\n颜色 × 尺码 的二维分布分析可以精准预测SKU级别的市场需求，是制版和采购的重要参考依据。',
'颜色下单率,销售结构,颜色分布,尺码分布,SKU分析,备货策略', 'system');
